const http = require('http');
const { URL } = require('url');
const vm = require('vm');
const crypto = require('crypto');

const PORT = process.env.PORT || 3000;
const OPENAI_API_KEY = process.env.OPENAI_API_KEY;
const OPENAI_MODEL = process.env.OPENAI_MODEL || 'gpt-4o-mini';

if (!OPENAI_API_KEY) {
  console.error('Missing OPENAI_API_KEY');
  process.exit(1);
}

function readJson(req) {
  return new Promise((resolve, reject) => {
    let body = '';
    req.on('data', chunk => {
      body += chunk;
      if (body.length > 1_000_000) {
        reject(new Error('Payload too large'));
        req.destroy();
      }
    });
    req.on('end', () => {
      try {
        resolve(body ? JSON.parse(body) : {});
      } catch {
        reject(new Error('Invalid JSON'));
      }
    });
    req.on('error', reject);
  });
}

function send(res, status, data) {
  res.writeHead(status, { 'Content-Type': 'application/json; charset=utf-8' });
  res.end(JSON.stringify(data));
}

async function generateCode(description, input) {
  const system = [
    'You are a code generation engine for a no-code automation platform.',
    'Return only valid JavaScript source code.',
    'The code must define an async function named main(input).',
    'The function must return a JSON-serializable value.',
    'Do not include markdown fences or explanations.',
    'Do not require external npm packages.',
    'Use only standard JavaScript supported by Node.js.',
  ].join(' ');

  const user = JSON.stringify({ description, input });

  const response = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${OPENAI_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      model: OPENAI_MODEL,
      temperature: 0.2,
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user },
      ],
    }),
  });

  if (!response.ok) {
    const text = await response.text();
    throw new Error(`LLM request failed: ${response.status} ${text}`);
  }

  const data = await response.json();
  const code = data?.choices?.[0]?.message?.content?.trim();

  if (!code) throw new Error('Empty code returned by model');
  return code;
}

async function executeCode(code, input) {
  const logs = [];
  const sandbox = {
    console: {
      log: (...args) => logs.push(args.map(v => String(v)).join(' ')),
      error: (...args) => logs.push(args.map(v => String(v)).join(' ')),
      warn: (...args) => logs.push(args.map(v => String(v)).join(' ')),
    },
    setTimeout,
    setInterval,
    clearTimeout,
    clearInterval,
    Buffer,
    URL,
    TextEncoder,
    TextDecoder,
    crypto,
    fetch,
  };

  const context = vm.createContext(sandbox);

  const wrapped = `
    "use strict";
    ${code}
    if (typeof main !== 'function') {
      throw new Error('Generated code must define async function main(input)');
    }
    globalThis.__runner = main;
  `;

  new vm.Script(wrapped, { timeout: 3000 }).runInContext(context, { timeout: 3000 });

  const result = await Promise.race([
    context.__runner(input),
    new Promise((_, reject) => setTimeout(() => reject(new Error('Execution timed out')), 5000)),
  ]);

  return { result, logs };
}

const server = http.createServer(async (req, res) => {
  const url = new URL(req.url, `http://${req.headers.host}`);

  if (req.method === 'GET' && url.pathname === '/health') {
    return send(res, 200, { ok: true });
  }

  if (req.method === 'POST' && url.pathname === '/generate-and-run') {
    try {
      const body = await readJson(req);
      const description = body?.description;
      const input = body?.input ?? {};

      if (!description || typeof description !== 'string') {
        return send(res, 400, { error: 'description is required' });
      }

      const code = await generateCode(description, input);
      const execution = await executeCode(code, input);

      return send(res, 200, {
        code,
        output: execution.result,
        logs: execution.logs,
      });
    } catch (err) {
      return send(res, 500, { error: err.message || 'Internal error' });
    }
  }

  send(res, 404, { error: 'Not found' });
});

server.listen(PORT, () => {
  console.log(`Server listening on port ${PORT}`);
});